{"content":"import React, { useState, useMemo, useCallback, useEffect, lazy, Suspense } from 'react';
import { User, AnalysisResult, SMCContent, GeneratedSolution } from './types';
import { analyzeUrl } from './services/analyzer';
import { db } from './services/database';
import Home from './pages/Home';
import Login from './pages/Login';
import Analyze from './pages/Analyze';

// Lazy-loaded pages for bundle optimization
const Dashboard = lazy(() => import('./pages/Dashboard'));
const GenerativeTools = lazy(() => import('./pages/GenerativeTools'));
const Results = lazy(() => import('./pages/Results').then(m => ({ default: m.Results })));
const HistoryView = lazy(() => import('./pages/History'));
const SMCStudio = lazy(() => import('./pages/SMCStudio'));
const SourceOfTruth = lazy(() => import('./pages/SourceOfTruth'));
const SchemaOrg = lazy(() => import('./pages/SchemaOrg'));
const PublisherRequest = lazy(() => import('./pages/PublisherRequest'));
const RobotsTxt = lazy(() => import('./pages/RobotsTxt'));
const Directory = lazy(() => import('./pages/Directory'));
const DirectoryEntity = lazy(() => import('./pages/DirectoryEntity'));
const Recharge = lazy(() => import('./pages/Recharge'));
const Projects = lazy(() => import('./pages/Projects'));
const Account = lazy(() => import('./pages/Account'));
const Clients = lazy(() => import('./pages/Clients'));
const Affiliation = lazy(() => import('./pages/Affiliation'));
const ContentWriter = lazy(() => import('./pages/ContentWriter'));
const Reputation = lazy(() => import('./pages/Reputation'));
const BotTracking = lazy(() => import('./pages/BotTracking'));
const Messages = lazy(() => import('./pages/Messages'));
const AlertsAEO = lazy(() => import('./pages/AlertsAEO'));
const MissionOrders = lazy(() => import('./pages/MissionOrders'));
import {
  LogOut, Zap, Github, Twitter, Linkedin, Home as HomeIcon, LayoutDashboard,
  Globe, ScanLine, Menu, CreditCard, FolderOpen, FileText, FileCode, History,
  Fuel, User as UserIcon, PenTool, Code, ClipboardList, ChevronDown, ChevronRight,
  Archive, CheckSquare, Sparkles, Users, MessageSquare, Bell, ShoppingBag,
  Settings, Construction, BarChart3, Wrench, Share2, Feather, Shield, X,
  Search, Activity, BookOpen, UserCircle
} from 'lucide-react';
import { I18nProvider, useTranslation, LanguageSelector } from './i18n';

const PLAN_LIMITS = {
  free: 1,
  pro: 3,
  enterprise: 1000 // Illimité en pratique
};

const App: React.FC = () => {
  return (
    <I18nProvider>
      <AppContent />
    </I18nProvider>
  );
};

const AppContent: React.FC = () => {
  const { t, tf, locale } = useTranslation();
  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders'>('home');
  const [viewHistory, setViewHistory] = useState<string[]>([]);
  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components

  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
  const [history, setHistory] = useState<AnalysisResult[]>([]);

  // Load history from DB on mount
  useEffect(() => {
    const loadedHistory = db.getAll();
    setHistory(loadedHistory);
  }, []);

  // Bibliothèques de contenu généré
  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);

  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');

  // État pour gérer l'ouverture des sections du menu (Accordion exclusif)
  const [sectionsState, setSectionsState] = useState({
    optimization: false,
    tools: false
  });
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Default user is NULL to allow testing the login flow
  const [user, setUser] = useState<User | null>(null);

  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
  const monthlyProjectCount = useMemo(() => {
    if (history.length === 0) return 0;

    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
    const now = new Date();
    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);

    // 1. Identifier la date de création (première analyse) de chaque domaine
    const projectCreationDates = new Map<string, Date>();

    history.forEach(h => {
        let hostname;
        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }

        const analysisDate = new Date(h.timestamp);

        if (!projectCreationDates.has(hostname)) {
            projectCreationDates.set(hostname, analysisDate);
        } else {
            // On garde la date la plus ancienne trouvée pour ce domaine
            if (analysisDate < projectCreationDates.get(hostname)!) {
                projectCreationDates.set(hostname, analysisDate);
            }
        }
    });

    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
    let count = 0;
    projectCreationDates.forEach((creationDate) => {
        if (creationDate >= billingCycleStart) {
            count++;
        }
    });

    return count;
  }, [history]);

  // Vérifier si le plan d'action est complet (toutes les recommendations ont une solution générée)
  const actionPlanStatus = useMemo(() => {
    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
    const latest = history[history.length - 1];
    const total = latest.recommendations.length;
    const completed = latest.recommendations.filter(rec =>
      latest.generatedSolutions?.[rec.id]
    ).length;
    return { complete: total > 0 && completed === total, completed, total };
  }, [history]);

  const navigateTo = (view: typeof currentView) => {
    setIsMobileMenuOpen(false);
    // Si on navigue vers autre chose que recharge, on reset l'ID du pack
    if (view !== 'recharge') {
        setInitialRechargePackId(null);
    }
    // Reset l'onglet du compte si on ne va pas vers le compte
    if (view !== 'account') {
        setInitialAccountTab('profile');
    }
    setViewHistory(prev => [...prev, currentView]);
    setCurrentView(view);
    setRefreshKey(prev => prev + 1); // Force remount to reset internal state of views
  };

  const goBack = () => {
    setIsMobileMenuOpen(false);
    if (viewHistory.length > 0) {
      const newHistory = [...viewHistory];
      const prevView = newHistory.pop();
      setViewHistory(newHistory);
      if (prevView) {
        setCurrentView(prevView as any);
        setRefreshKey(prev => prev + 1);
      }
    } else {
      setCurrentView('home'); // Default fallback
      setRefreshKey(prev => prev + 1);
    }
  };

  const toggleSection = (section: keyof typeof sectionsState) => {
    setSectionsState(prev => {
      const isAlreadyOpen = prev[section];
      return {
        optimization: false,
        tools: false,
        [section]: !isAlreadyOpen
      };
    });
  };

  const handleHomeClick = () => {
    navigateTo('home');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleDashboardClick = () => {
    navigateTo('dashboard');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleRechargeClick = () => {
    navigateTo('recharge');
    setSectionsState({
      optimization: false,
      tools: false
    });
  };

  const handleDirectRecharge = (packId: number) => {
    setInitialRechargePackId(packId);
    navigateTo('recharge');
  };

  const handleAnalyze = async (url: string) => {
    // Vérification de la limite de projets (Quota mensuel)
    if (user) {
        const limit = PLAN_LIMITS[user.plan] || 1;
        let hostname = url;
        try { hostname = new URL(url).hostname; } catch(e) {}

        // On vérifie si c'est un projet déjà existant dans l'historique global
        const isExistingProject = history.some(h => {
            try { return new URL(h.url).hostname === hostname; } 
            catch(e) { return false; }
        });

        // Si c'est un tout nouveau projet et qu'on a atteint la limite MENSUELLE
        // Les anciens projets ne comptent pas dans cette limite
        if (!isExistingProject && monthlyProjectCount >= limit) {
            // Redirection vers l'onglet Abonnement
            alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan supérieur pour ajouter plus de projets.`);
            setInitialAccountTab('subscription');
            navigateTo('account');
            return;
        }
    }

    setIsAnalyzing(true);
    try {
      const result = await analyzeUrl(url);
      setAnalysisData(result);

      // Update history via DB service
      const updatedHistory = db.add(result);
      setHistory(updatedHistory);

      // Redirection vers Monitoring AEO → onglet Rapport d'Audit
      setResultsTab('details');
      navigateTo('projects');
      setSectionsState({
        optimization: false,
        tools: false
      });
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Erreur lors de l'analyse. Veuillez réessayer.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  // Used for Admin/User private analysis view
  const handleViewAnalysis = (result: AnalysisResult, tab: any = 'overview') => {
    setAnalysisData(result);
    setResultsTab(tab);
    // Redirect to Projects (Monitoring AEO) instead of Results (Report)
    navigateTo('projects');
    setSectionsState({
        optimization: true,
        tools: false
    });
  };

  // New handler for Public Directory View
  const handleViewDirectoryEntity = (result: AnalysisResult) => {
    setAnalysisData(result);
    navigateTo('directory-entity');
  };

  const handleSubMenuNavigation = (tab: 'overview' | 'details' | 'archives') => {
    if (analysisData) {
      setResultsTab(tab);
      navigateTo('results');
    } else if (history.length > 0) {
      handleViewAnalysis(history[0], tab);
    } else {
      alert("Veuillez d'abord lancer une analyse pour accéder au plan d'actions.");
      navigateTo('analyze');
    }
  };

  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
    const updatedHistory = db.update(index, updatedData);
    setHistory(updatedHistory);
  };

  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
    const timestamp = new Date().toISOString();
    const solutionWithMeta = { ...solution, timestamp };

    setAnalysisData(prev => {
        if (!prev || prev.timestamp !== analysisId) return prev;

        return {
            ...prev,
            generatedSolutions: {
                ...(prev.generatedSolutions || {}),
                [recommendationId]: solutionWithMeta
            }
        };
    });

    // We need to find the index in the history to update the DB
    setHistory(prevHistory => {
        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
        if (index !== -1) {
            const updatedItem = {
                ...prevHistory[index],
                generatedSolutions: {
                    ...(prevHistory[index].generatedSolutions || {}),
                    [recommendationId]: solutionWithMeta
                }
            };
            // Persist using db service
            const newHistory = [...prevHistory];
            newHistory[index] = updatedItem;
            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
            db.update(index, updatedItem);
            return newHistory;
        }
        return prevHistory;
    });
  }, []); 

  // Helpers pour ajouter du contenu aux bibliothèques
  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);

  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
    setPublisherRequestData(data);
    navigateTo('publisher-request');
  };

  const handleNavigateToDirectory = () => {
    navigateTo('directory');
  };

  const handleDeductCredits = (amount: number): boolean => {
    if (!user) {
        if(confirm("Vous devez être connecté pour effectuer cette action. Se connecter maintenant ?")) {
            navigateTo('login');
        }
        return false;
    }

    if (user.credits < amount) {
        // Redirection explicite vers la section GTO Gas (Recharge)
        alert(`Solde GTO Gas insuffisant pour générer cette solution.\n\nIl vous manque ${amount - user.credits} crédits.\n\nRedirection vers la station de recharge...`);
        navigateTo('recharge');
        return false;
    }

    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
    return true;
  };

  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
    if (!user) return;

    setUser({ 
        ...user, 
        credits: user.credits + amount,
        plan: planLevel 
    });

    // Si c'est une recharge depuis la page de recharge, on ne force pas le retour, l'UX est gérée dans Recharge.tsx
  };

  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
    if (!user) return;
    setUser({ ...user, plan: newPlan });
  };

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    // On réinitialise l'historique pour éviter que le bouton retour ne renvoie au login
    // et on force la navigation vers le dashboard
    setViewHistory(['home']); 
    setCurrentView('analyze'); // Redirection vers Nouvel Audit
    setRefreshKey(prev => prev + 1);
  };

  const handleLogout = () => {
    setIsMobileMenuOpen(false);
    setUser(null);
    setCurrentView('home');
    setViewHistory([]);
    setRefreshKey(prev => prev + 1);
  };

  useEffect(() => {
    if (!user && isMobileMenuOpen) {
      setIsMobileMenuOpen(false);
    }
  }, [user, isMobileMenuOpen]);

  useEffect(() => {
    if (!isMobileMenuOpen) return;
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = previousOverflow;
    };
  }, [isMobileMenuOpen]);

  const NavItem = ({ view, label, icon: Icon, onClick, active, collapsed }: { view?: typeof currentView, label: string, icon: React.ElementType, onClick?: () => void, active?: boolean, collapsed?: boolean }) => {
    const handleClick = onClick ? onClick : () => view && navigateTo(view);
    const isActive = active !== undefined ? active : (view && currentView === view);

    if (collapsed) {
      return (
        <button
          onClick={handleClick}
          title={label}
          className={`w-full flex items-center justify-center py-2.5 rounded-xl transition-all duration-200 group ${
            isActive
              ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white shadow-lg shadow-purple-900/30'
              : 'text-gray-400 hover:text-white hover:bg-white/[0.06]'
          }`}
        >
          <Icon size={18} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
        </button>
      );
    }

    return (
      <button
        onClick={handleClick}
        className={`w-full flex items-center gap-3 px-3.5 py-2.5 rounded-xl text-[13.5px] transition-all duration-200 group font-sans ${
          isActive
            ? 'bg-gradient-to-r from-purple-600 to-violet-600 text-white font-semibold shadow-lg shadow-purple-900/30'
            : 'text-gray-400 hover:text-white hover:bg-white/[0.06] font-medium'
        }`}
      >
        <Icon size={17} className={isActive ? "text-white" : "text-gray-500 group-hover:text-gray-300"} />
        <span>{label}</span>
      </button>
    );
  };

  const PlaceholderView = ({ title, icon: Icon }: { title: string, icon: React.ElementType }) => (
    <div className="flex flex-col items-center justify-center h-[80vh] text-center p-8 animate-in fade-in zoom-in duration-300">
      <div className="w-24 h-24 bg-white/5 rounded-full flex items-center justify-center mb-6 shadow-inner border border-white/10">
        <Icon size={48} className="text-gray-500 opacity-50" />
      </div>
      <h2 className="text-3xl font-serif font-bold text-white mb-4">{title}</h2>
      <p className="text-gray-400 max-w-md mb-8">
        {t.common.featureInDev}
      </p>
      <button
        onClick={() => navigateTo('dashboard')}
        className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-xl transition-all flex items-center gap-2 font-medium"
      >
        <LayoutDashboard size={18} /> {t.common.returnToDashboard}
      </button>
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans text-gray-100 selection:bg-primary/30 bg-black">
      {/* Fixed Full-Width Navbar */}
      <nav className="fixed top-0 left-0 right-0 z-50 bg-[#0e0e18] border-b border-white/[0.06] shadow-lg shadow-black/30">
        <div className="px-6 h-14 flex items-center justify-between">
          <div className="flex items-center gap-2.5">
            {user && (
              <button
                type="button"
                onClick={() => setIsMobileMenuOpen(prev => !prev)}
                className="md:hidden w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors flex items-center justify-center"
                aria-label={isMobileMenuOpen ? "Fermer le menu" : "Ouvrir le menu"}
                aria-expanded={isMobileMenuOpen}
                aria-controls="mobile-sidebar-menu"
              >
                {isMobileMenuOpen ? <X size={17} /> : <Menu size={17} />}
              </button>
            )}
            {user && (
              <button
                type="button"
                onClick={() => setIsSidebarCollapsed(prev => !prev)}
                className="hidden md:flex w-9 h-9 rounded-full border border-white/[0.08] bg-white/[0.03] text-gray-300 hover:text-white hover:bg-white/[0.06] transition-colors items-center justify-center"
                aria-label={isSidebarCollapsed ? "Ouvrir le menu" : "Réduire le menu"}
              >
                <Menu size={17} />
              </button>
            )}
            <div
              className="flex items-center gap-2.5 cursor-pointer"
              onClick={() => navigateTo('home')}
            >
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center shadow-lg shadow-purple-900/40">
              <Zap size={16} className="text-white fill-white" />
            </div>
            <span className="font-sans text-lg font-bold tracking-tight hidden sm:block">
              <span className="text-white">CitedBy</span><span className="text-amber-400">.ai</span>
            </span>
            </div>
          </div>

          <div className="flex items-center gap-5">
            {user ? (
              <div className="flex items-center gap-3">
                <LanguageSelector compact />
                {/* Bell notification */}
                <button
                  onClick={() => navigateTo('alerts')}
                  className="relative w-9 h-9 rounded-full bg-white/[0.04] border border-white/[0.06] flex items-center justify-center text-gray-400 hover:text-white hover:bg-white/[0.08] transition-colors"
                  title="Notifications"
                >
                  <Bell size={16} />
                  <span className="absolute -top-0.5 -right-0.5 w-3 h-3 bg-amber-500 rounded-full border-2 border-[#0e0e18]"></span>
                </button>
                {/* Credits badge */}
                <button
                  onClick={() => navigateTo('recharge')}
                  className="hidden md:flex items-center gap-2 px-3.5 py-1.5 rounded-full bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500/20 transition-colors group"
                  title="Recharger GTO Gas"
                >
                  <Fuel size={14} className="text-amber-400" />
                  <span className="text-sm font-bold text-amber-400">{user.credits.toLocaleString()}</span>
                  <span className="text-xs text-amber-400/70 font-medium">Credits</span>
                </button>
                <div className="flex items-center gap-2.5">
                   <div
                     className="text-right hidden sm:block cursor-pointer"
                     onClick={() => navigateTo('account')}
                   >
                     <p className="text-sm font-semibold text-white leading-none hover:text-purple-400 transition-colors">{user.name}</p>
                     <p className="text-[10px] text-gray-500 uppercase tracking-wider mt-0.5">{user.plan === 'free' ? 'Admin' : user.plan.toUpperCase()}</p>
                   </div>
                   <button
                    title="Mon Compte"
                    onClick={() => navigateTo('account')}
                    className="w-9 h-9 rounded-full bg-gradient-to-br from-purple-500/20 to-violet-500/20 border border-purple-500/30 text-purple-300 text-sm font-bold flex items-center justify-center hover:border-purple-400/50 transition-colors"
                   >
                     {user.name.charAt(0).toUpperCase()}
                   </button>
                </div>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <LanguageSelector compact />
                <button
                  onClick={() => navigateTo('login')}
                  className="btn-gradient text-sm !py-2 !px-5"
                >
                  {t.nav.login}
                </button>
              </div>
            )}
          </div>
        </div>
      </nav>
      {/* Spacer for fixed navbar */}
      <div className="h-14 shrink-0" />

      {user && (
        <>
          <div
            className={`md:hidden fixed inset-0 z-40 bg-black/70 backdrop-blur-sm transition-opacity duration-300 ${
              isMobileMenuOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'
            }`}
            onClick={() => setIsMobileMenuOpen(false)}
          />
          <aside
            id="mobile-sidebar-menu"
            className={`md:hidden fixed top-0 left-0 bottom-0 z-50 w-[84%] max-w-[320px] bg-[#0e0e18] border-r border-white/[0.08] shadow-2xl shadow-black/50 transform transition-transform duration-300 ease-out ${
              isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'
            }`}
          >
            <div className="h-full flex flex-col pt-20 pb-6 px-4 overflow-y-auto">
              <div className="bg-[#13131d]/80 border border-white/[0.06] rounded-2xl p-3 space-y-1">
                <NavItem label={t.nav.home} icon={HomeIcon} view="home" />
                <NavItem label={t.nav.newAudit} icon={Search} view="analyze" />
                <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" />
                <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} />
                <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking'].includes(currentView)} />
                <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} />
                <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" />
                <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" />
                <NavItem label="Base Clients" icon={Users} view="clients" />
                <NavItem label="Ordres de Mission" icon={FileText} view="mission-orders" />
                <NavItem label="Alertes AEO" icon={Bell} view="alerts" />

                <div className="my-4 border-t border-white/[0.08] mx-4"></div>

                <NavItem label="Compte & Plan" icon={UserCircle} view="account" />
              </div>
            </div>
          </aside>
        </>
      )}

      <div className="flex-grow flex flex-col md:flex-row w-full relative">
        {user && (
          <aside className={`hidden md:flex flex-col py-4 sticky top-14 h-[calc(100vh-3.5rem)] overflow-y-auto transition-all duration-300 shrink-0 ${
            isSidebarCollapsed ? 'w-[68px] px-2' : 'w-64 px-3'
          }`}>
            <div className={`bg-[#13131d]/80 border border-white/[0.06] rounded-2xl shadow-lg overflow-y-auto custom-scrollbar ${
              isSidebarCollapsed ? 'p-1.5 space-y-0.5' : 'p-3 space-y-1'
            }`}>
               <NavItem label={t.nav.home} icon={HomeIcon} view="home" collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.newAudit} icon={Search} view="analyze" collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.dashboard} icon={LayoutDashboard} view="dashboard" collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.monitoringAEO} icon={Activity} view="projects" active={['projects', 'results'].includes(currentView)} collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.generativeTools} icon={Sparkles} view="generative-tools" active={['generative-tools', 'smc-studio', 'source-of-truth', 'schema-org', 'robots-txt', 'content-writer', 'reputation', 'bot-tracking'].includes(currentView)} collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.indexedDirectory} icon={BookOpen} view="directory" active={['directory', 'directory-entity'].includes(currentView)} collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.gtoGas} icon={Fuel} view="recharge" collapsed={isSidebarCollapsed} />
               <NavItem label={t.nav.affiliation} icon={Share2} view="affiliation" collapsed={isSidebarCollapsed} />
               <NavItem label="Base Clients" icon={Users} view="clients" collapsed={isSidebarCollapsed} />
               <NavItem label="Ordres de Mission" icon={FileText} view="mission-orders" collapsed={isSidebarCollapsed} />
               <NavItem label="Alertes AEO" icon={Bell} view="alerts" collapsed={isSidebarCollapsed} />

               <div className={`my-3 border-t border-white/10 ${isSidebarCollapsed ? 'mx-1' : 'mx-4'}`}></div>

               <NavItem label="Compte & Plan" icon={UserCircle} view="account" collapsed={isSidebarCollapsed} />
            </div>
          </aside>
        )}

        <main className="flex-1 w-full min-w-0 pb-20 md:pb-0">
          <Suspense fallback={<div className="flex items-center justify-center h-[60vh]"><div className="w-8 h-8 border-2 border-purple-500/30 border-t-purple-500 rounded-full animate-spin"></div></div>}>
          {currentView === 'home' && (
            <Home 
                key={`home-${refreshKey}`}
                onNavigate={(view) => navigateTo(view)} 
                user={user} 
                onDirectRecharge={handleDirectRecharge}
            />
          )}

          {currentView === 'login' && (
            <Login key={`login-${refreshKey}`} onLogin={handleLogin} onBack={goBack} />
          )}

          {currentView === 'dashboard' && (
            <Dashboard 
                key={`dashboard-${refreshKey}`}
                onBack={goBack} 
                history={history} 
                onView={handleViewAnalysis}
                onNavigate={navigateTo}
            />
          )}

          {currentView === 'generative-tools' && (
            <GenerativeTools key={`generative-tools-${refreshKey}`} onNavigate={navigateTo} />
          )}

          {currentView === 'analyze' && (
            <Analyze key={`analyze-${refreshKey}`} onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />
          )}

          {currentView === 'results' && analysisData && (
            <Results 
              key={`results-${refreshKey}`}
              data={analysisData} 
              onBack={goBack} 
              user={user}
              onDeductCredits={handleDeductCredits}
              onSaveSolution={handleSaveSolution}
              initialTab={resultsTab as any}
              onNewAnalysis={() => navigateTo('analyze')}
            />
          )}

          {currentView === 'history' && (
            <HistoryView
              key={`history-${refreshKey}`}
              onBack={goBack}
              history={history}
              onView={handleViewAnalysis}
            />
          )}

          {currentView === 'smc-studio' && (
            <SMCStudio 
              key={`smc-studio-${refreshKey}`}
              onBack={goBack} 
              user={user}
              onDeductCredits={handleDeductCredits}
              library={smcLibrary}
              onAddToLibrary={handleAddToSmcLibrary}
              onNavigateToPublisher={handleNavigateToPublisher}
              onNavigateToDirectory={handleNavigateToDirectory}
            />
          )}

          {currentView === 'source-of-truth' && (
            <SourceOfTruth 
              key={`source-of-truth-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              savedFiles={truthLibrary}
              onSaveFile={handleAddToTruthLibrary}
            />
          )}

          {currentView === 'schema-org' && (
            <SchemaOrg 
              key={`schema-org-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              savedFiles={schemaLibrary}
              onSaveFile={handleAddToSchemaLibrary}
            />
          )}

          {currentView === 'publisher-request' && (
            <PublisherRequest 
              key={`publisher-request-${refreshKey}`}
              onBack={goBack}
              user={user}
              data={publisherRequestData}
            />
          )}

          {currentView === 'robots-txt' && (
            <RobotsTxt 
              key={`robots-txt-${refreshKey}`}
              onBack={goBack} 
              history={history}
              user={user}
              onDeductCredits={handleDeductCredits}
              onUpdateAnalysis={handleUpdateAnalysis}
              savedFiles={robotsLibrary}
              onSaveFile={handleAddToRobotsLibrary}
            />
          )}

          {currentView === 'directory' && (
            <Directory
              key={`directory-${refreshKey}`}
              onBack={goBack}
              onViewEntity={handleViewDirectoryEntity}
              onNavigateToPlan={() => {
                setInitialAccountTab('subscription');
                navigateTo('account');
              }}
              user={user}
              directClientCount={monthlyProjectCount}
              maxClients={user ? PLAN_LIMITS[user.plan] : 1}
              actionPlanComplete={actionPlanStatus.complete}
              actionPlanProgress={actionPlanStatus}
              onNavigateToActionPlan={() => {
                setResultsTab('recommendations');
                navigateTo('projects');
              }}
            />
          )}

          {/* Nouvelle vue Directory Entity (Public Profile) */}
          {currentView === 'directory-entity' && analysisData && (
            <DirectoryEntity 
              key={`directory-entity-${refreshKey}`}
              data={analysisData}
              onBack={goBack}
            />
          )}

          {currentView === 'recharge' && (
            <Recharge 
              key={`recharge-${refreshKey}`}
              onBack={goBack} 
              onRecharge={handleRecharge}
              user={user}
              onNavigate={(view) => navigateTo(view as typeof currentView)} 
              initialPackId={initialRechargePackId}
            />
          )}

          {currentView === 'projects' && (
            <Projects
              key={`projects-${refreshKey}`}
              onBack={goBack}
              onNavigateToAnalysis={() => navigateTo('analyze')}
              user={user}
              history={history}
              onViewAnalysis={handleViewAnalysis}
              projectCount={monthlyProjectCount}
              maxProjects={user ? PLAN_LIMITS[user.plan] : 1}
              onNavigateToPlan={() => {
                setInitialAccountTab('subscription');
                navigateTo('account');
              }}
              onDeductCredits={handleDeductCredits}
              onSaveSolution={handleSaveSolution}
              onNewAnalysis={() => navigateTo('analyze')}
              onNavigateToRecharge={() => navigateTo('recharge')}
              initialUrl={analysisData?.url}
              initialTab={resultsTab}
            />
          )}

          {currentView === 'account' && (
            <Account
              key={`account-${refreshKey}`}
              user={user}
              onLogout={handleLogout}
              onNavigate={navigateTo}
              onUpgrade={handleUpgradePlan}
              projectCount={monthlyProjectCount}
              maxProjects={user ? PLAN_LIMITS[user.plan] : 1}
              initialTab={initialAccountTab}
            />
          )}

          {/* Client Database View */}
          {currentView === 'clients' && (
            <Clients
              key={`clients-${refreshKey}`}
              onBack={goBack}
              onNavigate={(view) => navigateTo(view as typeof currentView)}
              user={user}
              directClientCount={monthlyProjectCount}
              maxClients={user ? PLAN_LIMITS[user.plan] : 1}
            />
          )}

          {/* Affiliation Database View */}
          {currentView === 'affiliation' && (
            <Affiliation
              key={`affiliation-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}

          {/* AI Content Writer B2B */}
          {currentView === 'content-writer' && (
            <ContentWriter
              key={`content-writer-${refreshKey}`}
              onBack={goBack}
              user={user}
              onDeductCredits={handleDeductCredits}
            />
          )}

          {/* Reputation & Sentiment IA */}
          {currentView === 'reputation' && (
            <Reputation
              key={`reputation-${refreshKey}`}
              onBack={goBack}
              user={user}
              onDeductCredits={handleDeductCredits}
            />
          )}

          {/* Bot Tracking - Activation & Suivi des Bots IA */}
          {currentView === 'bot-tracking' && (
            <BotTracking
              key={`bot-tracking-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}

          {/* Messagerie */}
          {currentView === 'messages' && (
            <Messages
              key={`messages-${refreshKey}`}
              onBack={goBack}
              user={user}
            />
          )}
          {currentView === 'alerts' && (
            <AlertsAEO
              key={`alerts-aeo-${refreshKey}`}
              onBack={goBack}
              user={user}
              onNavigate={(view) => navigateTo(view as typeof currentView)}
            />
          )}

          {/* Ordres de Mission */}
          {currentView === 'mission-orders' && (
            <MissionOrders
              key={`mission-orders-${refreshKey}`}
              onBack={goBack}
              user={user}
              onNavigate={(view) => navigateTo(view as typeof currentView)}
            />
          )}
          </Suspense>
        </main>
      </div>

      {user && (
        <div className={`md:hidden fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-lg border-t border-white/[0.06] z-50 pb-safe transition-opacity duration-200 ${
          isMobileMenuOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'
        }`}>
          <div className="flex justify-around items-center h-16 px-2">
            {[
              { view: 'dashboard', icon: LayoutDashboard, label: t.nav.dash },
              { view: 'projects', icon: FolderOpen, label: t.nav.projects },
              { view: 'analyze', icon: ScanLine, label: t.nav.audit },
              { view: 'account', icon: UserIcon, label: t.nav.account }
            ].map((item) => (
              <button
                key={item.view}
                onClick={() => navigateTo(item.view as any)}
                className={`flex flex-col items-center justify-center w-full h-full space-y-1 ${
                  currentView === item.view ? 'text-primary' : 'text-gray-500'
                }`}
              >
                <item.icon size={20} className={currentView === item.view ? 'fill-primary/20' : ''} />
                <span className="text-[10px] font-medium">{item.label}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      <footer className={`border-t border-white/[0.06] bg-black mt-auto ${user ? 'pb-20 md:pb-0' : ''}`}>
        <div className="w-full px-4 py-16">
          <div className="grid md:grid-cols-4 gap-12 mb-12">
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center shadow-lg shadow-purple-900/40">
                  <Zap size={16} className="text-white fill-white" />
                </div>
                <span className="text-xl font-bold tracking-tight">
                  <span className="text-white">CitedBy</span><span className="text-amber-400">.ai</span>
                </span>
              </div>
              <p className="text-sm text-gray-400 leading-relaxed">
                {t.footer.tagline}
              </p>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.product}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><button onClick={() => navigateTo('analyze')} className="hover:text-primary transition-colors text-left">{t.footer.freeAudit}</button></li>
                <li><button onClick={() => navigateTo('directory')} className="hover:text-primary transition-colors text-left">{t.footer.indexDirectory}</button></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.devApi}</a></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.aeoResources}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.schemaGuide}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.llmFunctioning}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.aiComparison}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.techBlog}</a></li>
              </ul>
            </div>
            <div>
              <h4 className="font-bold text-white mb-6">{t.footer.company}</h4>
              <ul className="space-y-3 text-sm text-gray-400">
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.about}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.contact}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.legal}</a></li>
                <li><a href="#" className="hover:text-primary transition-colors">{t.footer.privacy}</a></li>
              </ul>
            </div>
          </div>
          <div className="border-t border-white/5 pt-8 flex flex-col md:flex-row justify-between items-center text-xs text-gray-500">
            <p>{t.footer.copyright}</p>
            <div className="flex gap-2 items-center mt-4 md:mt-0">
               <span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse"></span>
               {t.common.operationalSystems}
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
"}

{"content":"import React, { useState, useEffect } from 'react';
import { User } from '../types';
import {
  User as UserIcon, Mail, Key, Bell, LogOut, Fuel, Check, Copy, AlertTriangle,
  Droplet, Database, CreditCard, ShieldCheck, LayoutList, History, FileText,
  Download, Loader2, Sparkles, FolderOpen, TrendingUp, Zap, ArrowUpRight
} from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';

interface AccountProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (view: any) => void;
  onUpgrade: (plan: 'free' | 'pro' | 'enterprise') => void;
  projectCount: number;
  maxProjects: number;
  initialTab?: 'profile' | 'subscription' | 'billing';
}

const Account: React.FC<AccountProps> = ({ user, onLogout, onNavigate, onUpgrade, projectCount, maxProjects, initialTab = 'profile' }) => {
  const [activeTab, setActiveTab] = useState<'profile' | 'subscription' | 'billing'>(initialTab);
  const [apiKeyCopied, setApiKeyCopied] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [upgradeModal, setUpgradeModal] = useState<{ planId: string; planName: string; newPrice: number } | null>(null);
  const [paymentStep, setPaymentStep] = useState<'recap' | 'payment' | 'success'>('recap');
  const [paidAmount, setPaidAmount] = useState(0);
  const [paymentHistory, setPaymentHistory] = useState([
    { id: 'INV-2024-003', date: '01/03/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-002', date: '01/02/2024', amount: 89.00, desc: 'Abonnement Pro (Mensuel)', status: 'Payé' },
    { id: 'INV-2024-001', date: '15/01/2024', amount: 49.00, desc: 'Pack GTO Gas (La Pompe)', status: 'Payé' },
  ]);

  useEffect(() => {
    setActiveTab(initialTab);
  }, [initialTab]);

  if (!user) return null;

  // ── Helpers ──

  const handleCopyApiKey = () => {
    navigator.clipboard.writeText(`cb_pk_live_${user.id.substring(0, 8)}_${Math.random().toString(36).substr(2, 9)}`);
    setApiKeyCopied(true);
    setTimeout(() => setApiKeyCopied(false), 2000);
  };

  const getPlanDetails = (plan: string) => {
    switch (plan) {
      case 'enterprise':
        return { name: 'Agency', marketingName: 'La Citerne', icon: <Database size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-500 border-white/[0.1] shadow-[0_0_15px_rgba(168,85,247,0.1)]' };
      case 'pro':
        return { name: 'Pro', marketingName: 'La Pompe', icon: <Fuel size={14} className="fill-current" />, style: 'bg-purple-500/10 text-purple-400 border-primary/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' };
      default:
        return { name: 'Starter', marketingName: 'Le Jerrican', icon: <Droplet size={14} />, style: 'bg-white/[0.04] text-gray-300 border-white/[0.08]' };
    }
  };

  const planDetails = getPlanDetails(user.plan);
  const projectPercentage = maxProjects >= 1000 ? 15 : Math.min((projectCount / maxProjects) * 100, 100);
  const isAtLimit = projectCount >= maxProjects && maxProjects < 1000;

  // ── Pricing data ──

  const plans = [
    {
      id: 'free', name: 'Starter', price: 29, period: '/mois',
      icon: <Droplet size={24} />, current: user.plan === 'free',
      features: ['1 Projet Actif / mois', 'Audit manuel', 'Support communauté'],
      cta: 'Plan Actuel',
    },
    {
      id: 'pro', name: 'Pro', price: 89, period: '/mois', popular: true,
      icon: <Fuel size={24} />, current: user.plan === 'pro',
      features: ['Indexation IA', '3 Projets Actifs / mois', 'Monitoring Continu', 'Support Prioritaire', 'API Access (Beta)', 'Rapports PDF marque blanche'],
      cta: 'Passer Pro',
    },
    {
      id: 'enterprise', name: 'Agency', price: 299, period: '/mois',
      icon: <Database size={24} />, current: user.plan === 'enterprise',
      features: ['Indexation IA', 'Projets illimités', 'Dedicated Account Manager', 'API Full Access', 'SSO & Sécurité avancée', 'Formation AEO équipe'],
      cta: 'Passer Agency',
    },
  ];

  // Prix du plan actuel de l'utilisateur
  const currentPlanPrice = user.plan === 'enterprise' ? 299 : user.plan === 'pro' ? 89 : 29;

  const handleUpgradeClick = (planId: string) => {
    const targetPlan = plans.find(p => p.id === planId);
    if (!targetPlan || targetPlan.current) return;
    setUpgradeModal({ planId, planName: targetPlan.name, newPrice: targetPlan.price });
    setPaymentStep('payment');
  };

  const handleProcessPayment = () => {
    if (!upgradeModal) return;
    setIsProcessing(true);
    setTimeout(() => {
      const amountPaid = upgradeModal.newPrice - currentPlanPrice;
      const now = new Date();
      const dateStr = now.toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
      const invoiceNum = `INV-${now.getFullYear()}-${String(paymentHistory.length + 1).padStart(3, '0')}`;
      const newInvoice = {
        id: invoiceNum,
        date: dateStr,
        amount: amountPaid,
        desc: `Upgrade ${planDetails.name} → ${upgradeModal.planName} (Prorata)`,
        status: 'Payé',
      };
      setPaymentHistory(prev => [newInvoice, ...prev]);
      setPaidAmount(amountPaid);
      onUpgrade(upgradeModal.planId as any);
      setIsProcessing(false);
      setPaymentStep('success');
    }, 2500);
  };

  const handleCloseUpgradeModal = () => {
    setUpgradeModal(null);
    setPaymentStep('recap');
    setPaidAmount(0);
  };

  // ── Invoice PDF ──

  const generateInvoice = (payment: { id: string; date: string; amount: number; desc: string; status: string }) => {
    const doc = new jsPDF();
    doc.setFontSize(22);
    doc.setFont('helvetica', 'bold');
    doc.text('CitedBy.ai', 20, 20);
    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Facture N° ${payment.id}`, 20, 30);
    doc.text(`Date : ${payment.date}`, 20, 35);
    doc.text('Facturé à :', 140, 30);
    doc.setFont('helvetica', 'bold');
    doc.text(user.name || 'Client', 140, 35);
    doc.setFont('helvetica', 'normal');
    doc.text(user.email || '', 140, 40);
    doc.line(20, 55, 190, 55);
    doc.setFont('helvetica', 'bold');
    doc.text('Description', 20, 62);
    doc.text('Montant HT', 160, 62);
    doc.line(20, 66, 190, 66);
    const priceHT = (payment.amount / 1.2).toFixed(2);
    const tva = (payment.amount - parseFloat(priceHT)).toFixed(2);
    doc.setFont('helvetica', 'normal');
    doc.text(payment.desc, 20, 75);
    doc.text(`${priceHT} €`, 160, 75);
    doc.line(20, 90, 190, 90);
    doc.text('Sous-total HT :', 130, 100);
    doc.text(`${priceHT} €`, 160, 100);
    doc.text('TVA (20%) :', 130, 107);
    doc.text(`${tva} €`, 160, 107);
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(12);
    doc.text('Total TTC :', 130, 117);
    doc.text(`${payment.amount.toFixed(2)} €`, 160, 117);
    doc.setFontSize(8);
    doc.setFont('helvetica', 'italic');
    doc.text('Merci de votre confiance. Paiement effectué par CB.', 20, 140);
    doc.save(`Facture_${payment.id}.pdf`);
  };

  // ── Render ──

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">

      {/* ── STEP 2 : PLEINE PAGE DE PAIEMENT (comme Recharge.tsx) ── */}
      {upgradeModal && paymentStep === 'payment' && (
        <div className="animate-in fade-in slide-in-from-right duration-500">
          <StripeCheckout
            mode="subscription"
            productName={`Plan ${upgradeModal.planName}`}
            productDescription={`Upgrade ${planDetails.name} → ${upgradeModal.planName}`}
            amount={upgradeModal.newPrice - currentPlanPrice}
            amountDetails={[
              { label: `Nouveau plan (${upgradeModal.planName})`, value: `${upgradeModal.newPrice.toFixed(2)} €` },
              { label: `Crédit plan ${planDetails.name}`, value: `- ${currentPlanPrice.toFixed(2)} €` },
              { label: 'À payer aujourd\'hui', value: `${(upgradeModal.newPrice - currentPlanPrice).toFixed(2)} €`, highlight: true, separator: true },
            ]}
            userEmail={user.email}
            onConfirm={handleProcessPayment}
            onBack={() => setPaymentStep('recap')}
            isProcessing={isProcessing}
          />
        </div>
      )}

      {/* Contenu principal — masqué pendant le paiement */}
      {!(upgradeModal && paymentStep === 'payment') && (<>

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-gradient-to-br from-purple-500 to-violet-600 rounded-2xl flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-purple-500/20 border-2 border-black">
            {user.name.charAt(0).toUpperCase()}
          </div>
          <div>
            <h1 className="text-3xl font-sans font-bold text-white">Compte & Plan</h1>
            <p className="text-gray-500 text-sm">Profil, abonnement, facturation</p>
          </div>
        </div>
        <button
          onClick={onLogout}
          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-colors text-sm font-medium"
        >
          <LogOut size={16} /> Déconnexion
        </button>
      </div>

      {/* Tabs */}
      <div className="flex justify-center mb-10">
        <div className="inline-flex bg-white/[0.04] p-1.5 rounded-2xl border border-white/[0.08] flex-wrap justify-center gap-1">
          {([
            { key: 'profile', icon: UserIcon, label: 'Profil' },
            { key: 'subscription', icon: ShieldCheck, label: 'Abonnement & Projets' },
            { key: 'billing', icon: CreditCard, label: 'Facturation' },
          ] as const).map(tab => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`px-5 py-2.5 rounded-2xl text-sm font-bold transition-all flex items-center gap-2 ${
                activeTab === tab.key
                  ? 'bg-gradient-to-r from-purple-500 to-violet-600 text-white shadow-lg'
