                    Vous êtes maintenant sur le plan <span className="text-purple-400 font-bold">{upgradeModal.planName}</span>.
                  </p>
                </div>
                <div className="bg-white/[0.03] rounded-xl border border-white/[0.06] p-4 space-y-2 text-left">
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Montant débité</span>
                    <span className="text-white font-bold">{paidAmount.toFixed(2)} €</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Moyen de paiement</span>
                    <span className="text-white">•••• 4242</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-gray-400">Prochain renouvellement</span>
                    <span className="text-white">{upgradeModal.newPrice}€/mois</span>
                  </div>
                </div>
                <div className="flex gap-3 pt-2">
                  <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('subscription'); }}
                    className="flex-1 px-4 py-2.5 text-sm text-gray-400 hover:text-white border border-white/[0.08] rounded-xl transition-colors">
                    Mon abonnement
                  </button>
                  <button onClick={() => { handleCloseUpgradeModal(); setActiveTab('billing'); }}
                    className="flex-1 px-4 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 hover:from-purple-600 hover:to-violet-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-500/20 text-sm">
                    <FileText size={16} /> Voir ma facture
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default Account;
"}

{"content":"import React, { useState, useMemo, useEffect } from 'react';
import { Project, User, AnalysisResult, GeneratedSolution } from '../types';
import { Plus, Search, Globe, TrendingUp, Calendar, ArrowUpRight, BarChart3, ChevronDown, Zap, Activity, ArrowRight, Wrench, FileText, Shield, ExternalLink, Clock, LayoutDashboard, Bot, Lock, ChevronLeft, ChevronRight, Eye, RefreshCw, ClipboardList, ArrowLeft, ClipboardCheck, Archive, Code } from 'lucide-react';
import ScoreRing from '../components/ScoreRing';
import { Results } from './Results';
import ActionPlan from './ActionPlan';
import GenerationModal from '../components/GenerationModal';

interface ProjectsProps {
  onBack: () => void;
  onNavigateToAnalysis: () => void;
  user: User | null;
  history: AnalysisResult[];
  onViewAnalysis: (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview') => void;
  projectCount: number;
  maxProjects: number;
  onNavigateToPlan: () => void;
  onDeductCredits: (amount: number) => boolean;
  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
  onNewAnalysis: () => void;
  onNavigateToRecharge: () => void;
  initialUrl?: string;
  initialTab?: string;
}

// Helper to convert AnalysisResult to Project format
const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
  const hostname = new URL(analysis.url).hostname;
  return {
    id: `proj_${index}_${hostname}`,
    name: hostname,
    domain: analysis.url,
    status: 'active',
    lastRun: analysis.timestamp,
    visibilityScore: analysis.globalScore,
    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5), // Simulé basé sur le score
    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
  };
};

const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
  // Navigation internal state: monitoring | report | action-plan | archives
  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'archives'>(() => {
    if (initialTab === 'archives') return 'archives';
    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
    if (initialTab === 'details' || initialTab === 'report') return 'report';
    return 'monitoring';
  });

  useEffect(() => {
    if (initialTab === 'archives') setActiveTab('archives');
    else if (initialTab === 'recommendations') setActiveTab('action-plan');
    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
    else if (initialTab === 'overview') setActiveTab('monitoring');
  }, [initialTab]);

  // Use history to build project list, defaulting to mock if empty for demo
  const projects = useMemo(() => {
    if (history.length > 0) {
      // Deduplicate by URL hostname, keeping the most recent
      const uniqueMap = new Map<string, AnalysisResult>();
      history.forEach(item => {
        try {
            const host = new URL(item.url).hostname;
            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
                uniqueMap.set(host, item);
            }
        } catch(e) {}
      });
      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
    } else {
      // Mock data fallback if no history
      return [
        {
          id: 'demo_1',
          name: 'Exemple Site Demo',
          domain: 'https://demo-site.com',
          status: 'active',
          lastRun: new Date().toISOString(),
          visibilityScore: 45,
          trend: 0,
          nextRun: new Date(Date.now() + 86400000).toISOString()
        }
      ] as Project[];
    }
  }, [history]);

  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
    if (initialUrl && projects.length > 0) {
        try {
            const targetHost = new URL(initialUrl).hostname;
            // The projects mapping uses hostname as name
            const found = projects.find(p => p.name === targetHost);
            if (found) return found.id;
        } catch(e) {}
    }
    return projects[0]?.id || '';
  });

  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);

  // States for viewing archive modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);

  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];

  // Filter history for current project ONLY
  const projectHistory = useMemo(() => {
    return history
      .filter(h => {
          try { return new URL(h.url).hostname === currentProject.name; }
          catch(e) { return false; }
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [history, currentProject]);

  // Reset selected analysis when project changes
  useEffect(() => {
    setSelectedAnalysisState(null);
  }, [selectedProjectId]);

  // The analysis to display (either user-selected from table, or the latest one)
  const activeAnalysis = selectedAnalysisState || projectHistory[0];

  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
    setCurrentSolution(solution);
    setIsModalOpen(true);
  };

  // Calculate Pillar Scores from real categories if available
  const getPillarScores = () => {
    if (!activeAnalysis) {
      return {
        tech: 50,
        sem: 50,
        auth: 50
      };
    }

    const cats = activeAnalysis.categories;

    // Aggregation logic
    const techScore = Math.round(
      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
    );

    const semScore = Math.round(
      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
    );

    const authScore = Math.round(
      ((cats['entity']?.score || 0) + (cats['structured_data']?.score || 0) + (cats['trust']?.score || 0)) / 3
    );

    return { tech: techScore, sem: semScore, auth: authScore };
  };

  const pillarScores = getPillarScores();

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-white'; // Purple implied by bg bar
    if (score >= 60) return 'text-purple-400';
    return 'text-blue-400'; // For variation
  };

  const getBarColor = (score: number) => {
    if (score >= 80) return 'bg-purple-400';
    if (score >= 60) return 'bg-purple-500';
    return 'bg-blue-400';
  };

  const handleSwitchToReport = () => {
    if (activeAnalysis) {
        setActiveTab('report');
    } else {
        alert("Veuillez lancer une analyse pour voir le rapport.");
        onNavigateToAnalysis();
    }
  };

  const handleSwitchToActionPlan = () => {
    if (activeAnalysis) {
        setActiveTab('action-plan');
    } else {
        alert("Veuillez lancer une analyse pour voir le plan d'action.");
        onNavigateToAnalysis();
    }
  };

  const handleSwitchToArchives = () => {
    if (activeAnalysis) {
        setActiveTab('archives');
    } else {
        alert("Veuillez lancer une analyse pour voir les archives.");
        onNavigateToAnalysis();
    }
  };

  const handleBackToMonitoring = () => {
    setActiveTab('monitoring');
  };

  const isLimitReached = projectCount >= maxProjects;

  // -- SHARED TABS BAR (rendered on all views) --
  const [isProjectDropdownOpen, setIsProjectDropdownOpen] = useState(false);

  const renderTabsBar = () => (
    <div className="w-full px-4 pt-8">
      {/* URL Selector — prominent, above tabs */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 mb-6">
        <div className="relative">
          <button
            onClick={() => setIsProjectDropdownOpen(!isProjectDropdownOpen)}
            className="flex items-center gap-3 px-5 py-2.5 bg-gradient-to-r from-purple-500/10 to-violet-500/10 hover:from-purple-500/20 hover:to-violet-500/20 border border-purple-500/30 rounded-2xl transition-all text-sm font-bold group"
          >
            <Globe size={16} className="text-purple-400" />
            <span className="text-white truncate max-w-[280px]">{currentProject.name}</span>
            <ChevronDown size={14} className={`text-purple-400 transition-transform ${isProjectDropdownOpen ? 'rotate-180' : ''}`} />
          </button>
          {isProjectDropdownOpen && (
            <>
              <div className="fixed inset-0 z-40" onClick={() => setIsProjectDropdownOpen(false)} />
              <div className="absolute top-full left-0 mt-2 w-72 bg-[#1a1d24] border border-purple-500/20 rounded-2xl shadow-2xl shadow-purple-500/10 z-50 p-1.5 animate-in fade-in slide-in-from-top-2 duration-200">
                <p className="px-3 py-1.5 text-[10px] uppercase tracking-wider text-gray-500 font-bold">Projets scannés</p>
                {projects.map(p => (
                  <button
                    key={p.id}
                    onClick={() => { setSelectedProjectId(p.id); setIsProjectDropdownOpen(false); }}
                    className={`w-full text-left px-3 py-2.5 rounded-xl text-sm flex items-center gap-2.5 transition-colors ${
                      p.id === selectedProjectId
                        ? 'bg-purple-500/15 text-purple-300 font-bold'
                        : 'text-gray-300 hover:bg-white/[0.06]'
                    }`}
                  >
                    <Globe size={14} className={p.id === selectedProjectId ? 'text-purple-400' : 'text-gray-600'} />
                    {p.name}
                  </button>
                ))}
                <div className="border-t border-white/[0.06] mt-1.5 pt-1.5">
                  <button
                    onClick={() => { setIsProjectDropdownOpen(false); onNavigateToAnalysis(); }}
                    className="w-full text-left px-3 py-2.5 rounded-xl text-sm text-gray-500 hover:text-white hover:bg-white/[0.06] flex items-center gap-2.5 transition-colors"
                  >
                    <Plus size={14} /> Scanner une nouvelle URL
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
        {currentProject && (
          <span className="text-xs text-gray-500 flex items-center gap-1.5">
            <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-pulse"></span>
            Monitoring actif
          </span>
        )}
      </div>

      {/* Tabs */}
      <div className="flex gap-6 mb-8 border-b border-white/[0.08] overflow-x-auto">
          <button
            onClick={() => setActiveTab('monitoring')}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'monitoring'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Activity size={18} className={activeTab === 'monitoring' ? 'text-purple-400' : 'opacity-50'} />
            Vue d'ensemble
          </button>

          <button
            onClick={handleSwitchToReport}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'report'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <ClipboardList size={18} className={activeTab === 'report' ? 'text-purple-400' : 'opacity-50'} />
            Rapport d'Audit
          </button>

          <button
            onClick={handleSwitchToActionPlan}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'action-plan'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Zap size={18} className={activeTab === 'action-plan' ? 'text-purple-400 fill-primary' : 'opacity-50'} />
            Plan d'Action
            {activeAnalysis && activeAnalysis.recommendations.length > 0 && (
                <span className="bg-primary text-black text-[10px] px-1.5 py-0.5 rounded-full ml-1.5">
                    {activeAnalysis.recommendations.length}
                </span>
            )}
          </button>

          <button
            onClick={handleSwitchToArchives}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'archives'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Archive size={18} className={activeTab === 'archives' ? 'text-purple-400' : 'opacity-50'} />
            Archives Solutions
          </button>
      </div>
    </div>
  );

  // -- RENDER : REPORT VIEW (RESULTS) --
  if (activeTab === 'report' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              {renderTabsBar()}
              <Results 
                data={activeAnalysis} 
                onBack={handleBackToMonitoring}
                user={user}
                onDeductCredits={onDeductCredits}
                onSaveSolution={onSaveSolution}
                onNewAnalysis={onNewAnalysis}
              />
          </div>
      );
  }

  // -- RENDER : ACTION PLAN VIEW --
  if (activeTab === 'action-plan' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              {renderTabsBar()}
              <ActionPlan 
                data={activeAnalysis}
                user={user}
                onDeductCredits={onDeductCredits}
                onSaveSolution={onSaveSolution}
                onNavigateToAnalysis={onNewAnalysis}
                onNavigateToRecharge={onNavigateToRecharge}
              />
          </div>
      );
  }

  // -- RENDER : ARCHIVES SOLUTIONS VIEW --
  if (activeTab === 'archives' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300 w-full">
              {renderTabsBar()}
              <GenerationModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                isLoading={false}
                solution={currentSolution}
              />
              <div className="px-4 pb-8">

              <div className="flex items-center gap-3 mb-8">
                  <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-300 border border-purple-500/30">
                      <Archive size={20} />
                  </div>
                  <div>
                      <h3 className="text-xl font-sans font-bold text-white">Archives Solutions</h3>
                      <p className="text-sm text-gray-500">Retrouvez toutes les optimisations générées précédemment pour ce projet.</p>
                  </div>
              </div>

              {activeAnalysis.generatedSolutions && Object.keys(activeAnalysis.generatedSolutions).length > 0 ? (
                  <div className="grid md:grid-cols-2 gap-6">
                      {Object.entries(activeAnalysis.generatedSolutions).map(([recId, sol], idx) => {
                        const solution = sol as GeneratedSolution & { timestamp: string };
                        return (
                          <div key={recId} className="ninja-card p-5 rounded-2xl border border-white/[0.08] hover:border-purple-500/30 transition-all group cursor-pointer" onClick={() => handleOpenStoredSolution(solution)}>
                              <div className="flex justify-between items-start mb-3">
                                  <span className={`text-[10px] font-bold px-2 py-1 rounded uppercase tracking-wider ${solution.type === 'code' ? 'bg-blue-500/10 text-blue-400 border border-blue-500/20' : 'bg-pink-500/10 text-pink-400 border border-pink-500/20'}`}>
                                      {solution.type === 'code' ? 'Code Technique' : 'Contenu Éditorial'}
                                  </span>
                                  <span className="text-xs text-gray-500 flex items-center gap-1">
                                      <Clock size={10} />
                                      {new Date(solution.timestamp).toLocaleDateString()}
                                  </span>
                              </div>

                              <h4 className="font-bold text-white mb-2 line-clamp-1">{solution.title}</h4>
                              <p className="text-xs text-gray-500 mb-4 line-clamp-2">{solution.explanation}</p>

                              <div className="flex items-center justify-between pt-3 border-t border-white/[0.06]">
                                  <div className="flex items-center gap-2 text-xs text-gray-500">
                                      {solution.type === 'code' ? <Code size={12} /> : <FileText size={12} />}
                                      {solution.language}
                                  </div>
                                  <button className="text-xs font-bold text-purple-400 flex items-center gap-1 group-hover:underline">
                                      <Eye size={12} /> Voir
                                  </button>
                              </div>
                          </div>
                      )})}
                  </div>
              ) : (
                  <div className="ninja-card p-12 rounded-2xl border border-dashed border-white/[0.08] flex flex-col items-center justify-center text-center">
                      <div className="w-16 h-16 bg-white/[0.04] rounded-full flex items-center justify-center mb-4 text-gray-500">
                          <Archive size={32} />
                      </div>
                      <h4 className="text-lg font-medium text-white mb-2">Aucune archive disponible</h4>
                      <p className="text-sm text-gray-500 max-w-sm mb-6">
                          Les solutions que vous générez depuis l'onglet "Plan d'action" apparaîtront ici pour une consultation ultérieure.
                      </p>
                      <button 
                        onClick={handleSwitchToActionPlan}
                        className="text-purple-400 hover:text-white transition-colors text-sm font-bold flex items-center gap-2"
                      >
                        Générer ma première solution <ArrowRight size={14} />
                      </button>
                  </div>
              )}
              </div>
          </div>
      );
  }

  // -- RENDER : MONITORING DASHBOARD --
  return (
    <div className="w-full px-4 py-8 animate-in fade-in duration-500 min-h-screen">

      {/* HEADER: Project Selector & Actions */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
             <h1 className="text-3xl font-sans font-bold text-white">Monitoring AEO</h1>
          </div>
          <div className="flex items-center gap-4">
            <p className="text-gray-500 flex items-center gap-2 text-sm">
                <Globe size={14} /> {currentProject.domain}
                <span className="w-1 h-1 bg-gray-600 rounded-full"></span>
                <span className="text-purple-300">Monitoring Actif</span>
            </p>
            <div className="h-4 w-px bg-white/[0.08]"></div>
            <p className={`text-xs ${isLimitReached ? 'text-purple-400' : 'text-gray-500'}`}>
                {projectCount} / {maxProjects} Projets (Quota Mensuel)
            </p>
          </div>
        </div>

        <div className="flex gap-3">
           <button 
             onClick={isLimitReached ? onNavigateToPlan : onNavigateToAnalysis}
             className={`px-4 py-2.5 font-bold rounded-2xl transition-colors text-sm flex items-center gap-2 shadow-lg ${
                isLimitReached
                ? 'bg-purple-500 hover:bg-purple-600 text-white shadow-purple-500/20'
                : 'bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-600 hover:to-violet-700 shadow-primary/20'
             }`}
           >
             {isLimitReached ? <Lock size={16} /> : <Search size={16} />} 
             {isLimitReached ? 'Upgrade pour ajouter' : 'Scan Manuel'}
           </button>
        </div>
      </div>

      {/* TABS HEADER */}
      {renderTabsBar()}

      {/* SECTION 1: SCORING AEO (DYNAMIC DATA) */}
      <div className="mb-8">
         <div className="flex flex-col md:flex-row justify-between md:items-center mb-6 gap-4">
            <h2 className="text-xl font-medium text-white flex flex-wrap items-center gap-2">
                <Activity size={20} className="text-purple-400" />
                Score AEO pour : 
                <span className="text-purple-400 font-bold bg-purple-500/10 px-2 py-0.5 rounded text-base break-all">
                    {activeAnalysis ? activeAnalysis.url.replace(/^https?:\/\/(www\.)?/, '') : 'Aucune URL'}
                </span>
                {activeAnalysis && <span className="text-sm text-gray-500 font-normal whitespace-nowrap">({new Date(activeAnalysis.timestamp).toLocaleDateString()})</span>}
            </h2>
            {activeAnalysis && activeAnalysis !== projectHistory[0] && (
                <button 
                    onClick={() => setSelectedAnalysisState(null)} 
                    className="text-xs text-purple-400 hover:text-white transition-colors flex items-center gap-1 bg-white/[0.04] px-3 py-1.5 rounded-full border border-white/[0.08]"
                >
                    <RefreshCw size={12} /> Revenir à la dernière analyse
                </button>
            )}
         </div>

         <div className="grid md:grid-cols-12 gap-6">
            {/* Main Score */}
            <div className="md:col-span-4 ninja-card p-8 rounded-2xl flex flex-col items-center justify-center relative overflow-hidden border-primary/20">
               <div className="absolute top-0 right-0 w-32 h-32 bg-purple-500/10 blur-3xl rounded-full pointer-events-none"></div>
               <h3 className="text-gray-500 text-sm font-medium uppercase tracking-wider mb-6">Score de Visibilité Globale</h3>
               <ScoreRing score={activeAnalysis ? activeAnalysis.globalScore : 0} size={160} strokeWidth={12} />
               <div className="mt-6 flex items-center gap-2 px-3 py-1 bg-purple-500/10 border border-white/[0.1] rounded-full">
                  <TrendingUp size={14} className="text-purple-300" />
                  <span className="text-purple-300 text-sm font-bold">
                    {currentProject.trend > 0 ? '+' : ''}{currentProject.trend}% ce mois-ci
                  </span>
               </div>
            </div>

            {/* Pillars Breakdown - Calculated from Real Categories */}
            <div className="md:col-span-8 grid grid-cols-1 sm:grid-cols-3 gap-4">
               {/* Pilier 1: Technique */}
               <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex flex-col justify-between h-full group hover:border-blue-500/30 transition-colors">
                  <div>
                     <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-gray-500 text-xs uppercase mb-1">Infrastrucure</p>
                            <h4 className="text-white font-bold text-lg">Technique</h4>
                        </div>
                        <div className="p-2 bg-blue-500/10 rounded-full text-blue-400">
                            <Wrench size={18} />
                        </div>
                     </div>
                     <div className="space-y-3 mb-6">
                        <div className="flex justify-between items-end">
                           <span className={`text-3xl font-bold ${getScoreColor(pillarScores.tech)}`}>{pillarScores.tech}</span>
                           <span className="text-xs text-gray-500 mb-1">/100</span>
                        </div>
                        <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                           <div className={`h-full ${getBarColor(pillarScores.tech)}`} style={{ width: `${pillarScores.tech}%` }}></div>
                        </div>
                        <p className="text-xs text-gray-500 mt-2 min-h-[32px]">
                           {pillarScores.tech >= 80 ? "Excellente réactivité serveur." : "Latence ou problèmes d'indexation détectés."}
                        </p>
                     </div>
                  </div>
                  <button 
                    onClick={handleSwitchToActionPlan} 
                    className="w-full py-2.5 bg-blue-500/10 hover:bg-blue-500/20 text-blue-400 border border-blue-500/20 rounded-full text-sm font-bold transition-all flex items-center justify-center gap-2"
                  >
                    Voir les solutions <ArrowRight size={14} />
                  </button>
               </div>

               {/* Pilier 2: Sémantique */}
               <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex flex-col justify-between h-full group hover:border-purple-500/30 transition-colors">
                  <div>
                     <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-gray-500 text-xs uppercase mb-1">Contenu</p>
                            <h4 className="text-white font-bold text-lg">Sémantique</h4>
                        </div>
                        <div className="p-2 bg-purple-500/10 rounded-full text-purple-400">
                            <FileText size={18} />
                        </div>
                     </div>
                     <div className="space-y-3 mb-6">
                        <div className="flex justify-between items-end">
                           <span className={`text-3xl font-bold ${getScoreColor(pillarScores.sem)}`}>{pillarScores.sem}</span>
                           <span className="text-xs text-gray-500 mb-1">/100</span>
                        </div>
                        <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                           <div className={`h-full ${getBarColor(pillarScores.sem)}`} style={{ width: `${pillarScores.sem}%` }}></div>
                        </div>
                        <p className="text-xs text-gray-500 mt-2 min-h-[32px]">
                           {pillarScores.sem >= 80 ? "Structure Answer-First valide." : "Manque de structure pour le parsing IA."}
                        </p>
                     </div>
                  </div>
                  <button
                    onClick={handleSwitchToActionPlan}
                    className="w-full py-2.5 bg-purple-500/10 hover:bg-purple-500/20 text-purple-400 border border-white/[0.1] rounded-full text-sm font-bold transition-all flex items-center justify-center gap-2"
                  >
                    Voir les solutions <ArrowRight size={14} />
                  </button>
               </div>

               {/* Pilier 3: Autorité */}
               <div className="ninja-card p-5 rounded-2xl border border-white/[0.08] flex flex-col justify-between h-full group hover:border-purple-500/30 transition-colors">
                  <div>
                     <div className="flex justify-between items-start mb-4">
                        <div>
                            <p className="text-gray-500 text-xs uppercase mb-1">Autorité</p>
                            <h4 className="text-white font-bold text-lg">Entité Graph</h4>
                        </div>
                        <div className="p-2 bg-purple-500/10 rounded-full text-purple-300">
                            <Shield size={18} />
                        </div>
                     </div>
                     <div className="space-y-3 mb-6">
                        <div className="flex justify-between items-end">
                           <span className={`text-3xl font-bold ${getScoreColor(pillarScores.auth)}`}>{pillarScores.auth}</span>
                           <span className="text-xs text-gray-500 mb-1">/100</span>
                        </div>
                        <div className="w-full bg-gray-800 h-1.5 rounded-full overflow-hidden">
                           <div className={`h-full ${getBarColor(pillarScores.auth)}`} style={{ width: `${pillarScores.auth}%` }}></div>
                        </div>
                        <p className="text-xs text-gray-500 mt-2 min-h-[32px]">
                           {pillarScores.auth >= 80 ? "Entité clairement identifiée." : "Données structurées incomplètes."}
                        </p>
                     </div>
                  </div>
                  <button
                    onClick={handleSwitchToActionPlan}
                    className="w-full py-2.5 bg-purple-500/10 hover:bg-purple-500/20 text-purple-300 border border-white/[0.1] rounded-full text-sm font-bold transition-all flex items-center justify-center gap-2"
                  >
                    Voir les solutions <ArrowRight size={14} />
                  </button>
               </div>
            </div>
         </div>
      </div>

      {/* SECTION 2: HISTORIQUE DES ANALYSES */}
      <div className="ninja-card rounded-2xl overflow-hidden border border-white/[0.08] mt-8">
         <div className="p-6 border-b border-white/[0.08] flex justify-between items-center bg-white/[0.04]">
            <h3 className="font-bold text-white flex items-center gap-2">
               <Clock size={20} className="text-gray-500" /> Historique des analyses
            </h3>
            <div className="text-xs text-gray-500">
               {projectHistory.length} audits conservés
            </div>
         </div>

         <div className="overflow-x-auto">
            <table className="w-full text-left">
               <thead>
                  <tr className="bg-[#000000] text-xs text-gray-500 uppercase tracking-wider">
                     <th className="px-6 py-4 font-medium">Date</th>
                     <th className="px-6 py-4 font-medium">Score Global</th>
                     <th className="px-6 py-4 font-medium">Technique</th>
                     <th className="px-6 py-4 font-medium">Sémantique</th>
                     <th className="px-6 py-4 font-medium">Autorité</th>
                     <th className="px-6 py-4 font-medium text-right">Actions</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-white/5">
                  {projectHistory.map((analysis, idx) => (
                     <tr key={idx} className={`hover:bg-white/[0.02] transition-colors ${selectedAnalysisState === analysis ? 'bg-white/[0.04]' : ''}`}>
                        <td className="px-6 py-4 text-sm text-gray-300">
                           {new Date(analysis.timestamp).toLocaleDateString()} <span className="text-gray-600 text-xs ml-1">{new Date(analysis.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                        </td>
                        <td className="px-6 py-4">
                           <span className={`font-bold ${getScoreColor(analysis.globalScore)}`}>{analysis.globalScore}</span>
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-500">
                           {Math.round(analysis.categories['technical']?.score || 0)}
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-500">
                           {Math.round(analysis.categories['semantic']?.score || 0)}
                        </td>
                        <td className="px-6 py-4 text-sm text-gray-500">
                           {Math.round(analysis.categories['entity']?.score || 0)}
                        </td>
                        <td className="px-6 py-4 text-right flex justify-end gap-2">
                           <button 
                              onClick={() => {
                                 setSelectedAnalysisState(analysis);
                                 setActiveTab('report');
                                 window.scrollTo({ top: 0, behavior: 'smooth' });
                              }}
                              className="text-gray-500 hover:text-white text-xs font-bold px-3 py-1.5 rounded-full border border-white/[0.08] hover:bg-white/[0.04] transition-colors flex items-center gap-1"
                           >
                              <ClipboardList size={12} />
                              Rapport
                           </button>
                           <button 
                              onClick={() => {
                                 setSelectedAnalysisState(analysis);
                                 setActiveTab('action-plan');
                                 window.scrollTo({ top: 0, behavior: 'smooth' });
                              }}
                              className="text-purple-400 hover:text-white text-xs font-bold px-3 py-1.5 rounded-full border border-primary/20 hover:bg-purple-500/10 transition-colors flex items-center gap-1"
                           >
                              <Zap size={12} />
                              Plan d'Action
                           </button>
                        </td>
                     </tr>
                  ))}
                  {projectHistory.length === 0 && (
                     <tr>
                        <td colSpan={6} className="px-6 py-8 text-center text-gray-500 text-sm">
                           Aucune analyse enregistrée pour ce projet.
                        </td>
                     </tr>
                  )}
               </tbody>
            </table>
         </div>
      </div>

    </div>
  );
};

export default Projects;"}

{"content":"import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
import jsPDF from 'jspdf';
import StripeCheckout from '../components/StripeCheckout';

interface Props {
  onBack: () => void;
  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  user: User | null;
  onNavigate?: (view: string) => void;
  initialPackId?: number | null;
}

const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [invoiceId, setInvoiceId] = useState<string>('');

  const packs = [
    {
      id: 1,
      name: "Le Jerrican",
      amount: 50,
      price: 15,
      icon: <Droplet size={32} />,
      popular: false,
      level: 'free' as const,
      features: ["Idéal pour un audit ponctuel", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      amount: 200,
      price: 49,
      icon: <Fuel size={32} />,
      popular: true,
      level: 'pro' as const,
      features: ["Pour les optimisations régulières", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      amount: 1000,
      price: 199,
      icon: <Database size={32} />,
      popular: false,
      level: 'enterprise' as const,
      features: ["Usage intensif / Agence", "Accès API Beta", "+20% Bonus offert"]
    }
  ];

  // Effet pour sélectionner automatiquement un pack si initialPackId est fourni
  useEffect(() => {
    if (initialPackId) {
        const targetPack = packs.find(p => p.id === initialPackId);
        if (targetPack) {
            setSelectedPack(targetPack);
            setViewMode('checkout');
        }
    }
  }, [initialPackId]);

  const handleSelectPack = (pack: typeof packs[0]) => {
    setSelectedPack(pack);
    setViewMode('checkout');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleConfirmPayment = () => {
    if (!selectedPack) return;
    setIsProcessing(true);
    setPaymentStatus('idle');

    // Simulation délai paiement et résultat aléatoire (90% de succès pour l'UX)
    setTimeout(() => {
      const isSuccess = Math.random() > 0.1;

      if (isSuccess) {
        onRecharge(selectedPack.amount, selectedPack.level);
        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
        setInvoiceId(newInvoiceId);
        setPaymentStatus('success');
      } else {
        setPaymentStatus('error');
      }

      setIsProcessing(false);
      setViewMode('result');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }, 2000);
  };

  const generateInvoicePDF = () => {
    if (!selectedPack || !user) return;

    const doc = new jsPDF();
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;
    const date = new Date().toLocaleDateString('fr-FR');

    // Header
    doc.setFontSize(22);
    doc.setFont("helvetica", "bold");
    doc.text("CitedBy.ai", 20, 20);

    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Facture N° " + invoiceId, 20, 30);
    doc.text("Date : " + date, 20, 35);

    // Client Info
    doc.text("Facturé à :", 140, 30);
    doc.setFont("helvetica", "bold");
    doc.text(user.name || "Client", 140, 35);
    doc.setFont("helvetica", "normal");
    doc.text(user.email || "", 140, 40);

    // Line Items Header
    doc.line(20, 55, 190, 55);
    doc.setFont("helvetica", "bold");
    doc.text("Description", 20, 62);
    doc.text("Quantité", 120, 62);
    doc.text("Montant HT", 160, 62);
    doc.line(20, 66, 190, 66);

    // Item
    doc.setFont("helvetica", "normal");
    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
    doc.text("1", 125, 75);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);

    // Totals
    doc.line(20, 90, 190, 90);
    doc.text("Sous-total HT :", 130, 100);
    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);

    doc.text("TVA (20%) :", 130, 107);
    doc.text(`${tva.toFixed(2)} €`, 160, 107);

    doc.setFont("helvetica", "bold");
    doc.setFontSize(12);
    doc.text("Total TTC :", 130, 117);
    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);

    // Footer
    doc.setFontSize(8);
    doc.setFont("helvetica", "italic");
    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);

    doc.save(`Facture_${invoiceId}.pdf`);
  };

  const renderList = () => (
    <div className="animate-in fade-in slide-in-from-left duration-500">
        <div className="text-center mb-16">
            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
            <Fuel size={32} />
            </div>
            <h1 className="text-4xl font-bold text-white mb-4">GTO <span className="gradient-text">Gas Station</span></h1>
            <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Le carburant essentiel pour propulser votre visibilité dans les moteurs de réponse.
            <br />
            <span className="text-sm mt-2 block text-gray-500">Solde actuel : <span className="text-white font-bold">{user?.credits || 0} Gas</span></span>
            </p>
        </div>

        <div className="grid md:grid-cols-3 gap-8 w-full">
            {packs.map((pack) => (
            <div 
                key={pack.id} 
                className={`relative ninja-card p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
                pack.popular
                    ? 'gradient-border !border-purple-500/30 shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
                    : ''
                }`}
            >
                {pack.popular && (
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-accent text-white font-bold text-xs px-4 py-1 rounded-full uppercase tracking-wider">
                    Meilleure Offre
                </div>
                )}

                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/[0.04] text-gray-500'}`}>
                {pack.icon}
                </div>

                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
                <div className="flex items-baseline gap-1 mb-6">
                <span className="text-4xl font-bold gradient-text">{pack.amount}</span>
                <span className="text-sm text-gray-500 font-medium">Gas</span>
                </div>

                <ul className="space-y-3 mb-8 flex-1">
                {pack.features.map((feat, i) => (
                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
                    {feat}
                    </li>
                ))}
                </ul>

                <div className="border-t border-white/[0.08] pt-6 mb-6">
                <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-500">Prix HT</span>
                    <span className="text-xl font-bold text-white">{pack.price}€</span>
                </div>
                </div>

                <button
                onClick={() => handleSelectPack(pack)}
                className="w-full py-3.5 btn-gradient font-bold flex items-center justify-center gap-2 transition-all"
                >
                    <CreditCard size={18} /> Acheter
                </button>
            </div>
            ))}
        </div>

        <p className="text-center text-gray-500 text-xs mt-12">
            Paiement sécurisé via Stripe • Facture disponible instantanément • TVA non incluse
        </p>
    </div>
  );

  const renderCheckout = () => {
    if (!selectedPack) return null;

    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    // Logique Upsell
    const showCiterneUpsell = selectedPack.name !== "La Citerne";
    const showSubscriptionUpsell = user?.plan === 'free';

    return (
        <div className="animate-in fade-in slide-in-from-right duration-500">
            <div className="grid lg:grid-cols-12 gap-8">

                {/* Colonne Gauche: Paiement */}
                <div className="lg:col-span-8">
                    <StripeCheckout
                      mode="one-time"
                      productName={selectedPack.name}
                      productDescription={`Pack de ${selectedPack.amount} cr\u00e9dits GTO Gas`}
                      productIcon={selectedPack.icon}
                      amount={totalTTC}
                      amountDetails={[
                        { label: 'Prix Unitaire HT', value: `${priceHT.toFixed(2)} \u20ac` },
                        { label: 'Frais de service', value: '0.00 \u20ac' },
                        { label: 'TVA (20%)', value: `${tva.toFixed(2)} \u20ac` },
                        { label: 'Total TTC', value: `${totalTTC.toFixed(2)} \u20ac`, highlight: true, separator: true },
                      ]}
                      userEmail={user?.email}
                      onConfirm={handleConfirmPayment}
                      onBack={() => setViewMode('list')}
                      isProcessing={isProcessing}
                    />
                </div>

                {/* Colonne Droite: Upsells */}
                <div className="lg:col-span-4 space-y-4">
                    <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-2">Recommandé pour vous</h3>

                    {/* Upsell Citerne */}
                    {showCiterneUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all" onClick={() => setSelectedPack(packs[2])}>
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg">
                                Meilleur Prix / Unité
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <Database size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Passez à la Citerne</h4>
                                    <p className="text-xs text-purple-200/70">Économisez 60%</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Obtenez <strong>1000 Crédits</strong> pour seulement 199€. Idéal pour les agences ou les refontes complètes.
                            </p>
                            <button className="w-full py-2 border border-white/[0.08] bg-white/[0.04] rounded-full text-purple-400 text-xs font-bold transition-colors hover:bg-white/[0.08]">
                                Choisir ce pack (199€)
                            </button>
                        </div>
                    )}

                    {/* Upsell Abonnement */}
                    {showSubscriptionUpsell && (
                        <div className="bg-gradient-to-br from-purple-900/40 to-black border border-purple-500/30 p-5 rounded-2xl relative overflow-hidden group cursor-pointer hover:border-purple-500/60 transition-all">
                            <div className="absolute top-0 right-0 px-2 py-1 bg-purple-500 text-white text-[10px] font-bold rounded-bl-lg flex items-center gap-1">
                                <Infinity size={10} /> Mensuel
                            </div>
                            <div className="flex items-center gap-3 mb-3">
                                <div className="p-2 bg-purple-500/20 rounded-full text-purple-400">
                                    <ShieldCheck size={20} />
                                </div>
                                <div>
                                    <h4 className="font-bold text-white text-sm">Activez le Monitoring</h4>
                                    <p className="text-xs text-purple-200/70">La Source</p>
                                </div>
                            </div>
                            <p className="text-xs text-gray-300 mb-3 leading-relaxed">
                                Ne perdez pas vos positions. Ajoutez l'indexation continue et la détection d'hallucinations.
                            </p>
                            <div className="flex items-center gap-2 mb-3">
                                <span className="text-lg font-bold text-white">89€</span>
                                <span className="text-xs text-gray-500">/mois</span>
                            </div>
                            <button className="w-full py-2 btn-gradient text-xs font-bold transition-colors">
                                Ajouter l'abonnement
                            </button>
                        </div>
                    )}

                    {!showCiterneUpsell && !showSubscriptionUpsell && (
                        <div className="p-5 rounded-2xl border border-white/[0.06] bg-white/[0.04] text-center">
                            <div className="w-12 h-12 bg-purple-400/10 rounded-full flex items-center justify-center text-purple-300 mx-auto mb-3">
                                <Check size={24} />
                            </div>
                            <p className="text-sm text-gray-300 font-medium">Vous avez choisi la meilleure offre pour vos besoins !</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
  };

  const renderPaymentResult = () => {
    if (!selectedPack) return null;

    // Status: ERROR
    if (paymentStatus === 'error') {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
                <div className="w-24 h-24 bg-red-500/20 rounded-full flex items-center justify-center mb-8 border border-red-500/50 shadow-[0_0_40px_rgba(239,68,68,0.3)]">
                    <XCircle size={48} className="text-red-500" />
                </div>

                <h2 className="text-4xl font-bold text-white mb-2">Paiement <span className="gradient-text">Refusé</span></h2>
                <p className="text-gray-500 text-center mb-10 text-lg">
                    La transaction n'a pas pu aboutir. Veuillez vérifier vos informations bancaires ou essayer une autre méthode de paiement.
                </p>

                <div className="flex gap-4 w-full">
                    <button
                        onClick={() => { setViewMode('list'); }}
                        className="flex-1 py-3.5 rounded-full font-bold border border-white/[0.08] bg-white/[0.04] text-white hover:bg-white/[0.08] transition-colors flex items-center justify-center gap-2"
                    >
                        <ArrowLeft size={18} /> Annuler
                    </button>
                    <button
                        onClick={() => { setViewMode('checkout'); }}
                        className="flex-1 py-3.5 btn-gradient font-bold transition-all flex items-center justify-center gap-2"
                    >
                        <RefreshCcw size={18} /> Réessayer
                    </button>
                </div>
            </div>
        );
    }

    // Status: SUCCESS
    const priceHT = selectedPack.price;
    const tva = priceHT * 0.20;
    const totalTTC = priceHT + tva;

    return (
        <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-500 max-w-2xl mx-auto">
            <div className="w-24 h-24 bg-purple-400/20 rounded-full flex items-center justify-center mb-8 border border-purple-400/50 shadow-[0_0_40px_rgba(168,85,247,0.3)]">
                <CheckCircle2 size={48} className="text-purple-400" />
            </div>

            <h2 className="text-4xl font-sans font-bold text-white mb-2">Paiement Accepté !</h2>
            <p className="text-gray-500 text-center mb-10 text-lg">
                Merci pour votre commande. Vos crédits <strong>{selectedPack.amount} GTO Gas</strong> ont été ajoutés à votre compte.
            </p>

            <div className="w-full bg-[#0f1115] border border-white/[0.08] rounded-2xl p-8 mb-8 relative overflow-hidden">
                <div className="absolute top-0 right-0 px-3 py-1 bg-white/[0.08] rounded-bl-lg text-xs text-gray-500 font-mono">
                    {invoiceId}
                </div>

                <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                    <FileText size={20} className="text-purple-400" /> Récapitulatif de commande
                </h3>

                <div className="space-y-4 text-sm">
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Produit</span>
                        <span className="font-medium text-white">{selectedPack.name}</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300">
                        <span>Quantité</span>
                        <span className="font-medium text-white">1</span>
                    </div>
                    <div className="flex justify-between items-center text-gray-300 border-b border-white/[0.08] pb-4">
                        <span>Date</span>
                        <span className="font-medium text-white">{new Date().toLocaleDateString()}</span>
                    </div>
                    <div className="flex justify-between items-center pt-2">
                        <span className="font-bold text-white text-lg">Total Payé</span>
                        <span className="font-bold text-xl text-purple-400">{totalTTC.toFixed(2)} €</span>
                    </div>
                </div>
            </div>

            {/* Buttons Navigation Succès */}
            <div className="flex flex-col md:flex-row gap-4 w-full">
                <button 
                    onClick={() => { onNavigate ? onNavigate('projects') : onBack(); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-white/[0.08] text-white hover:bg-white/20 transition-colors flex items-center justify-center gap-2"
                >
                    <Wrench size={18} /> Continuer l'analyse
                </button>
                <button 
                    onClick={() => { onNavigate ? onNavigate('plan') : console.log("Navigation vers plan non disponible"); }}
                    className="flex-1 py-3.5 rounded-2xl font-bold bg-primary hover:bg-purple-600 text-white transition-all shadow-lg shadow-primary/20 flex items-center justify-center gap-2"
                >
                    <CreditCard size={18} /> Voir Plan & Facturation
                </button>
            </div>

            <button 
                onClick={generateInvoicePDF}
                className="mt-6 text-sm text-gray-500 hover:text-white flex items-center gap-2 transition-colors"
            >
                <Download size={14} /> Télécharger la facture PDF
            </button>
        </div>
    );
  };

  return (
    <div className="w-full px-4 py-10 animate-in fade-in duration-500 min-h-screen">
        {viewMode === 'list' && renderList()}
        {viewMode === 'checkout' && renderCheckout()}
        {viewMode === 'result' && renderPaymentResult()}
    </div>
  );
};

export default Recharge;"}

